const now = new Date();
const chicago = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));

// Get day of week (0=Sun, 5=Fri, 6=Sat)
const dow = chicago.getDay();
// Saturday is next day (we run Friday)
const satOffset = dow === 5 ? 1 : 0;
const sat = new Date(chicago);
sat.setDate(chicago.getDate() + satOffset);
const sun = new Date(sat);
sun.setDate(sat.getDate() + 1);

function toISO(d) {
  return d.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
}

// ISO week number
function getWeekNum(d) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
}

const satDate = toISO(sat);
const sunDate = toISO(sun);
const weekNum = getWeekNum(sat);
const year = sat.getFullYear();

return [{ json: { satDate, sunDate, weekNum, year, generatedAt: now.toISOString() } }];

// Decode S3 binary to plain text for downstream cross-reference
let text = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  text = buf.toString('utf-8');
} catch(e) {}
return [{ json: { ...($input.first().json), _text: text } }];

// Get decoded MTL text
let mtlContent = '';
try { mtlContent = $('Decode MTL').first().json._text || ''; } catch(e) {}

// Get weekend dates
const { satDate, sunDate, weekNum, year } = $('Set Weekend Dates').first().json;
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });

// Parse Priority A rocks (open, no due date or due date in next 14 days)
const rocksA = [];
const re = /^- \[ \] (.+?)\[area:: ([^\]]+)\].*?\[priority:: A\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
let m;
while ((m = re.exec(mtlContent)) !== null) {
  const task = m[1].trim();
  const area = m[2];
  const due = m[3] || null;
  const cutoff = new Date(new Date().getTime() + 14*86400000).toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
  if (!due || due <= cutoff) {
    rocksA.push({ task, area, due });
  }
}

// Parse GCal events (graceful — may not exist)
const satEvents = [];
const sunEvents = [];
try {
  const satItems = $('GCal: Saturday Events').all();
  for (const item of satItems) {
    const e = item.json;
    if (e.summary && e.start) satEvents.push({ title: e.summary, start: e.start.dateTime || e.start.date, end: e.end?.dateTime || e.end?.date });
  }
} catch(e) {}
try {
  const sunItems = $('GCal: Sunday Events').all();
  for (const item of sunItems) {
    const e = item.json;
    if (e.summary && e.start) sunEvents.push({ title: e.summary, start: e.start.dateTime || e.start.date, end: e.end?.dateTime || e.end?.date });
  }
} catch(e) {}

// Always add church block to Sunday
const churchBlock = { title: '⛪ Church', start: `${sunDate}T08:30:00`, end: `${sunDate}T11:30:00`, hardBlock: true };
sunEvents.push(churchBlock);
sunEvents.sort((a, b) => (a.start || '').localeCompare(b.start || ''));

// Format time from ISO string
function fmtTime(iso) {
  if (!iso || !iso.includes('T')) return '';
  const [h, min] = iso.split('T')[1].split(':');
  const hr = parseInt(h);
  const ampm = hr >= 12 ? 'PM' : 'AM';
  return `${hr % 12 || 12}:${min} ${ampm}`;
}

// Build vault note (Obsidian callout format)
const satFmt = new Date(satDate + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', timeZone: 'America/Chicago' });
const sunFmt = new Date(sunDate + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', timeZone: 'America/Chicago' });
const noteKey = `40_Timeline_Weekly/Weekly/${year}-W${weekNum.toString().padStart(2,'0')}-weekend.md`;

const topRock = rocksA[0];
const topRockLine = topRock ? `**${topRock.task}** \`${topRock.area}\` \`A\`` : 'Review your Master Task List and set your weekend intention.';

function formatEventsObsidian(events) {
  if (!events.length) return '> *No events scheduled.*\n>';
  return events.map(e => {
    const time = e.start?.includes('T') ? `${fmtTime(e.start)}–${fmtTime(e.end)} ` : '';
    return `> - ${time}${e.title}`;
  }).join('\n') + '\n>';
}

const satLabel = satFmt.replace('Saturday, ', '');
const sunLabel = sunFmt.replace('Sunday, ', '');

const vaultNote = `---
type: weekend-plan
week: ${year}-W${weekNum.toString().padStart(2,'0')}
dates: ${satDate} — ${sunDate}
generated: ${new Date().toISOString()}
---

# 🗓️ Weekend Plan — ${satLabel} – ${sunLabel}

> [!tip] 🎯 Weekend Priority
> ${topRockLine}

> [!info]- 📅 ${satFmt}
>
${formatEventsObsidian(satEvents)}

> [!info]- 📅 ${sunFmt}
>
${formatEventsObsidian(sunEvents)}

> [!warning]- 🪓 Priority A Rocks — Move These Forward
>
${rocksA.slice(0, 8).map(r => `> - [ ] ${r.task} \`${r.area}\`${r.due ? ` [due:: ${r.due}]` : ''}`).join('\n')}
>

> [!note] ✍️ Weekend Intentions
> <!-- What do you want to accomplish this weekend? -->

---
*Auto-generated ${new Date().toISOString()} — ${rocksA.length} A-rocks, ${satEvents.length} Sat events, ${sunEvents.length} Sun events*
`;

// Build HTML email (same style as morning briefing)
const areaEmoji = { faith:'🙏', family:'👨\u200d👩\u200d👧', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🎯' };

function eventCard(e) {
  const time = e.start?.includes('T') ? `<span style="color:#6b7280;font-size:11px">${fmtTime(e.start)}–${fmtTime(e.end)}</span> ` : '';
  const bg = e.hardBlock ? '#fff3f3' : 'white';
  const border = e.hardBlock ? '#dc2626' : '#6366f1';
  return `<div style="border-left:3px solid ${border};background:${bg};padding:8px 12px;margin:3px 0;border-radius:0 4px 4px 0">${time}<strong style="font-size:13px">${e.title}</strong></div>`;
}

function rockCard(r) {
  const emoji = areaEmoji[r.area] || '📌';
  return `<div style="border-left:4px solid #2563eb;background:white;padding:10px 14px;margin:4px 0;border-radius:0 4px 4px 0"><span style="font-size:13px;font-weight:500">${emoji} ${r.task}</span><div style="font-size:11px;color:#9ca3af;margin-top:3px;text-transform:capitalize">${r.area}${r.due ? ` · due ${r.due}` : ''}</div></div>`;
}

let html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:0">';
html += `<div style="background:#1a1a2e;color:white;padding:24px 20px;border-radius:8px 8px 0 0"><h1 style="margin:0;font-size:22px;font-weight:700">🗓️ Weekend Plan</h1><p style="margin:6px 0 0;opacity:0.75;font-size:14px">${satFmt} – ${sunFmt}</p></div>`;

// Top priority CTA
html += `<div style="background:#2563eb;color:white;padding:14px 20px;margin:2px 0"><p style="margin:0;font-size:10px;text-transform:uppercase;letter-spacing:1.5px;opacity:0.85">🎯 WEEKEND PRIORITY</p><p style="margin:6px 0 0;font-size:15px;font-weight:bold;line-height:1.4">${topRock ? `${areaEmoji[topRock.area] || ''} ${topRock.task}` : 'Set your weekend intention'}</p></div>`;

// Saturday
html += `<div style="padding:16px 20px;background:#f0f4ff;margin-top:2px"><h2 style="margin:0 0 10px;font-size:15px;color:#1e40af;font-weight:700">📅 ${satFmt}</h2>`;
html += satEvents.length > 0 ? satEvents.map(eventCard).join('') : '<div style="color:#6b7280;font-size:13px">No events scheduled — open time!</div>';
html += '</div>';

// Sunday
html += `<div style="padding:16px 20px;background:#fff8f0;margin-top:2px"><h2 style="margin:0 0 10px;font-size:15px;color:#92400e;font-weight:700">📅 ${sunFmt}</h2>`;
html += sunEvents.map(eventCard).join('');
html += '</div>';

// Priority A rocks
if (rocksA.length > 0) {
  html += `<div style="padding:16px 20px;background:#f0f4ff;margin-top:2px"><h2 style="margin:0 0 10px;font-size:15px;color:#2563eb;font-weight:700">🪓 Priority A Rocks — This Weekend</h2>${rocksA.slice(0,6).map(rockCard).join('')}</div>`;
}

// Footer
html += `<div style="padding:14px 20px;background:#1a1a2e;border-radius:0 0 8px 8px;text-align:center"><p style="margin:0;color:#9ca3af;font-size:11px">${rocksA.length} A-rocks active · Weekend Plan auto-generated · Life OS</p></div>`;
html += '</div>';

const subject = `🗓️ Weekend Plan: ${satLabel} – ${sunLabel}`;

return [{ json: { html, vaultNote, noteKey, satDate, sunDate, weekNum, year, rockCount: rocksA.length, satEventCount: satEvents.length, sunEventCount: sunEvents.length, subject } }];

const vaultNote = $json.vaultNote;
const noteKey = $json.noteKey;
const fileName = noteKey.split('/').pop();
const buf = Buffer.from(vaultNote, 'utf-8');
return [{ json: $json, binary: { vaultNoteFile: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName, fileExtension: 'md', fileSize: buf.length } } }];

const j = $('Build Weekend Plan').first().json;
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const log = JSON.stringify({
  workflow: 'weekend-planner',
  run_date: today,
  finished_at: new Date().toISOString(),
  status: 'success',
  week: `${j.year}-W${j.weekNum.toString().padStart(2,'0')}`,
  sat_date: j.satDate,
  sun_date: j.sunDate,
  rock_count: j.rockCount,
  sat_event_count: j.satEventCount,
  sun_event_count: j.sunEventCount,
  note_key: j.noteKey
}, null, 2);
return [{ json: { logKey: `99_System/logs/weekend-planner-${today}.json`, logContent: log } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
